import sys, json

after = json.load(sys.stdin)
json.dump(after, open('after-cpm-packages.json','w'), indent=2)

with open('baseline-packages.json') as f:
    baseline = json.load(f)

# Compare
b_pkgs = {p['id']: p['resolvedVersion'] for p in baseline['projects'][0]['frameworks'][0]['topLevelPackages']}
a_pkgs = {p['id']: p['resolvedVersion'] for p in after['projects'][0]['frameworks'][0]['topLevelPackages']}

if b_pkgs == a_pkgs:
    print('All packages resolve to identical versions. Conversion is version-neutral.')
else:
    for pkg in sorted(set(list(b_pkgs.keys()) + list(a_pkgs.keys()))):
        bv = b_pkgs.get(pkg, 'MISSING')
        av = a_pkgs.get(pkg, 'MISSING')
        if bv != av:
            print(f'  CHANGED: {pkg}: {bv} -> {av}')
"

